const OPENAI_API_KEY = $env['OPENAI_API_KEY'];
const product = $input.first().json.product;
const topic = $input.first().json.topic;
const target_audience = $input.first().json.target_audience;

const SCRIPT_SYSTEM = `You are the creative director for @vitalessencehealth, a TikTok Shop brand with a wacky, fun, Pixar-style animated aesthetic. Your scripts are playful, emotionally resonant storytelling — like an animated short film where the product saves the day.

BRAND VOICE:
- Energetic, fun, and warm. Like a cartoon character who found the secret to feeling amazing.
- Wacky but relatable. Exaggerated reactions and situations are encouraged.
- Storytelling-first: the audience struggle is the hero. The product is the magical solution.
- Never salesy. The CTA lands naturally as the happy ending.

PRODUCT CONTEXT:
- vitamins: Daily supplement stack. Energy, mental clarity, filling nutritional gaps. Key emotion: I finally feel like the main character of my own life.
- gut_health: Digestive enzyme and probiotic blend. Bloating relief, gut-brain connection, food freedom. Key emotion: I can finally eat my favorite foods without my stomach staging a revolt.
- nobs_toothpaste: Toothpaste tablets — zero plastic, clean ingredients, travel-friendly. Whiter teeth, fresh breath, clean beauty. Key emotion: My bathroom routine just became the main character arc.

SCRIPT STRUCTURE — always follow this arc:
[HOOK 0-3s]: Wacky, surprising, stops the scroll. Exaggerated situation or bold question.
[PROBLEM 3-10s]: Relatable struggle told with humor and heart.
[DISCOVERY 10-20s]: Finding @vitalessencehealth. Feels like fate, not an ad.
[TRANSFORMATION 20-35s]: The animated glow-up. Specific, sensory, fun.
[CTA 35-45s]: Soft close pointing to TikTok Shop. One clear joyful action.

SCENE STRUCTURE:
Return exactly 20 scene descriptions. Scenes 1-17 are animated story moments (AI-generated Pixar style). Scenes 18-20 are CTA moments — describe them as IRL product shots that the creator will film themselves (TikTok Shop overlay, product closeup, creator holding product).

OUTPUT FORMAT strict JSON no markdown:
{"voiceover": "<clean voiceover 75-115 words>", "scenes": ["<scene 1 description>", "<scene 2 description>", ..., "<scene 20 description>"], "hook": "<scroll-stopping first line>", "cta": "<final CTA line>"}`;

const SCORER_SYSTEM = `You are a TikTok quality judge for @vitalessencehealth. Score on 5 criteria 1-5 each. Pass threshold is 18 out of 25.

1. HOOK STRENGTH (1-5) — stops scroll in 3 seconds, wacky and surprising
2. EMOTIONAL ARC (1-5) — clear fun problem to magical solution journey
3. BRAND VOICE (1-5) — wacky Pixar energy, warm, not salesy
4. PRODUCT ACCURACY (1-5) — correct specific benefits, no compliance red flags
5. CTA EFFECTIVENESS (1-5) — natural happy ending pointing to TikTok Shop

OUTPUT strict JSON: {"total_score": <5-25>, "pass": <true if >=18>, "feedback": "<2-3 sentences>", "criteria_scores": {"hook_strength": <1-5>, "emotional_arc": <1-5>, "brand_voice": <1-5>, "product_accuracy": <1-5>, "cta_effectiveness": <1-5>}}`;

async function callOpenAI(messages, temperature, maxTokens) {
  const res = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${OPENAI_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'gpt-4o', messages, temperature, max_tokens: maxTokens, response_format: { type: 'json_object' } })
  });
  const data = await res.json();
  if (!res.ok) throw new Error('OpenAI error: ' + JSON.stringify(data.error || data));
  return JSON.parse(data.choices[0].message.content);
}

let attempt = 0, script = null, score = null, passed = false;

while (attempt < 3) {
  attempt++;
  script = await callOpenAI([
    { role: 'system', content: SCRIPT_SYSTEM },
    { role: 'user', content: `Write a TikTok script for @vitalessencehealth.\n\nProduct: ${product}\nTopic: ${topic}\nTarget Audience: ${target_audience}\n\nReturn strict JSON with exactly 20 scenes.` }
  ], 0.85, 1200);

  if (!Array.isArray(script.scenes) || script.scenes.length < 18) {
    script.scenes = (script.scenes || []).concat(Array(20).fill('Wacky animated scene')).slice(0, 20);
  }

  score = await callOpenAI([
    { role: 'system', content: SCORER_SYSTEM },
    { role: 'user', content: `Score this script.\n\nProduct: ${product}\nAudience: ${target_audience}\n\nScript: ${JSON.stringify(script)}\n\nReturn strict JSON.` }
  ], 0.2, 600);

  if (score.pass === true) { passed = true; break; }
}

return [{ json: { script, score, passed, attempt_count: attempt, product, topic, target_audience } }];

const FAL_API_KEY = $env['FAL_API_KEY'];

const scriptData = $('Code - Script Gen + Score Loop').item.json;
const script = scriptData.script;
const score = scriptData.score;
const product = scriptData.product;
const topic = scriptData.topic;
const target_audience = scriptData.target_audience;
const attempt_count = scriptData.attempt_count;
const folderId = $('Google Drive - Create Content Folder').item.json.id;

// Carry voiceover binary from ElevenLabs
const audioData = $('ElevenLabs - Adam Voiceover').item.binary?.voiceover_audio?.data || '';

// Wacky Pixar style — core suffix for all scenes
const PIXAR_STYLE = '3D animated Pixar style, vibrant saturated colors, wacky exaggerated cartoon characters, playful fun energy, bright cheerful lighting, Pixar movie render quality, clean animation aesthetic, no text overlays, no watermarks, no logos';

const productContext = {
  vitamins: 'cartoon health supplements, colorful capsules, animated wellness energy',
  gut_health: 'animated gut health, cartoon probiotic, happy stomach character, digestive wellness',
  nobs_toothpaste: 'cartoon toothpaste tablets, animated oral care, bright smile character, eco-friendly bathroom'
}[product] || 'animated health wellness product';

async function generateFluxImage(sceneDescription) {
  const prompt = `${sceneDescription}, ${productContext} | ${PIXAR_STYLE}`;
  const res = await fetch('https://fal.run/fal-ai/flux/schnell', {
    method: 'POST',
    headers: { 'Authorization': `Key ${FAL_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      prompt: prompt,
      image_size: 'portrait_16_9',
      num_inference_steps: 4,
      num_images: 1,
      enable_safety_checker: false
    })
  });
  const data = await res.json();
  if (!res.ok) throw new Error('Flux Schnell error: ' + JSON.stringify(data));

  // Download image and convert to base64
  const imgRes = await fetch(data.images[0].url);
  const buffer = await imgRes.arrayBuffer();
  return Buffer.from(buffer).toString('base64');
}

// Generate all 20 images in parallel
const scenes = script.scenes.slice(0, 20);
const imageB64Array = await Promise.all(scenes.map(generateFluxImage));

// Build images array (used by Split Out node downstream)
const images = scenes.map((scene, i) => ({
  index: i + 1,
  filename: `scene_${String(i + 1).padStart(2, '0')}.jpg`,
  b64: imageB64Array[i],
  description: scene,
  is_irl: i >= 17,
  folderId: folderId
}));

// Build script.txt content
const line = String.fromCharCode(9472).repeat(48);
const sceneList = scenes.map((s, i) => {
  const tag = i >= 17 ? ' [IRL — film this yourself]' : ' [AI Pixar image generated]';
  return `[SCENE ${String(i+1).padStart(2,'0')}]${tag}:\n${s}`;
}).join('\n\n');

const scriptText = `VITALESSENCE TIKTOK CONTENT PACKAGE\n${'='.repeat(50)}\n\nProduct: ${product}\nTopic: ${topic}\nTarget Audience: ${target_audience}\nGenerated: ${new Date().toISOString()}\nImage Style: Wacky Pixar 3D Animated (Flux Schnell)\n\n${line}\nSCORE REPORT\n${line}\nTotal: ${score.total_score}/25 — ${score.pass ? 'PASSED' : 'FAILED'}  |  Attempts: ${attempt_count}\n  Hook Strength:     ${score.criteria_scores.hook_strength}/5\n  Emotional Arc:     ${score.criteria_scores.emotional_arc}/5\n  Brand Voice:       ${score.criteria_scores.brand_voice}/5\n  Product Accuracy:  ${score.criteria_scores.product_accuracy}/5\n  CTA Effectiveness: ${score.criteria_scores.cta_effectiveness}/5\nFeedback: ${score.feedback}\n\n${line}\nSCRIPT\n${line}\nHOOK: ${script.hook}\n\nVOICEOVER:\n${script.voiceover}\n\nCTA: ${script.cta}\n\n${line}\n20 SCENE DESCRIPTIONS\n${line}\nScenes 01-17: AI-generated Pixar-style images (in this Drive folder)\nScenes 18-20: IRL footage — film yourself with the product for these\n\n${sceneList}\n\n${line}\nEDITING NOTES\n${line}\n1. Import scene images (01-17) as background slides in CapCut\n2. Layer voiceover.mp3 over the timeline\n3. Replace scenes 18-20 with your IRL product footage\n4. Add TikTok Shop product link sticker on the CTA frame\n5. Export 1080x1920 for TikTok\n`;

return [{
  json: { script, score, product, topic, target_audience, attempt_count, folderId, scriptText, images, total_images: images.length },
  binary: {
    voiceover_audio: { data: audioData, mimeType: 'audio/mpeg', fileName: 'voiceover.mp3' }
  }
}];

const item = $input.first().json;
return [{
  json: { filename: item.filename, index: item.index, folderId: item.folderId },
  binary: {
    image: { data: item.b64, mimeType: 'image/jpeg', fileName: item.filename }
  }
}];
